import json

europe_metadata = locals()['var_functions.query_db:16']
if isinstance(europe_metadata, str):
    with open(europe_metadata, 'r') as f:
        europe_metadata = json.load(f)

# Group articles by year and extract article IDs
europe_articles_by_year = {}
years = range(2010, 2021)

for y in years:
    europe_articles_by_year[y] = []

for item in europe_metadata:
    year = int(item['publication_date'][:4])
    article_id = str(item['article_id'])
    if 2010 <= year <= 2020:
        europe_articles_by_year[year].append(article_id)

# Count total
all_europe_ids = []
for y in years:
    all_europe_ids.extend(europe_articles_by_year[y])

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(all_europe_ids),
    'by_year': {y: len(europe_articles_by_year[y]) for y in years},
    'sample_ids': all_europe_ids[:5]
}))

