# Load Europe metadata and prepare batches
import json, math

europe_metadata = locals()['var_functions.query_db:16']
if isinstance(europe_metadata, str):
    with open(europe_metadata, 'r') as f:
        europe_metadata = json.load(f)

# Get unique article IDs
europe_article_ids = list(set([item['article_id'] for item in europe_metadata]))

# Group by year first
year_to_ids = {}
for y in range(2010, 2021):
    year_to_ids[y] = []

for item in europe_metadata:
    year = int(item['publication_date'][:4])
    if 2010 <= year <= 2020:
        year_to_ids[year].append(item['article_id'])

print('__RESULT__:')
print(json.dumps({
    'total_europe_articles': len(europe_article_ids),
    'articles_by_year': {y: len(ids) for y, ids in year_to_ids.items()},
    'sample_ids': europe_article_ids[:5],
    'batches_needed': math.ceil(len(europe_article_ids) / 5000)
}))

